mapper.select:
SELECT
    POST_ID AS postId,
    USER_ID AS userId
FROM COMMUNITY_LIKE
WHERE POST_ID = #{postId}
  AND USER_ID = #{userId}

mapper.insert:
INSERT INTO COMMUNITY_LIKE (
    POST_ID, USER_ID, CREATED_AT, CREATED_BY, UPDATED_AT, UPDATED_BY
) VALUES (
             #{postId}, #{userId}, NOW(), #{userId}, NOW(), #{userId}
         )

mapper.delete:
DELETE FROM COMMUNITY_LIKE
WHERE POST_ID = #{postId}
  AND USER_ID = #{userId}

